@startuml
title CrossoverOperators's Class Diagram

package "Logic" as Logic {
  package "Operators" as Operators {
    package "CrossoverOperators" as CrossoverOperators {
      class CrossoverOperationType {
        - COMPX
        - MEAN
        - MPX
        - OPC
        - TPC
        - UC
        - crossoverOperator
        - text
      }

      class CrossoverOperator {
        + generateChild()
        + isCompatible()
        + isSymmetric()
      }

      class CompositionCrossover {
        + generateChild()
        + isCompatible()
        + isSymmetric()
      }

      class MaximalPreservationCrossover {
        - rand : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setSeed()
      }

      class OnePointCrossover {
        - RNG : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setRandomSeed()
      }

      class UniformCrossover {
        - RNG : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setRandomSeed()
      }

      class TwoPointCrossover {
        - RNG : Random
        + generateChild()
        + isCompatible()
        + isSymmetric()
        + setRandomSeed()
      }

      class OrdinalNumberMean {
        + OrdinalNumberMean()
        + generateChild()
        + isCompatible()
        + isSymmetric()
      }

      CrossoverOperationType ..> CrossoverOperator : crossoverOperator
      CompositionCrossover <|-- CrossoverOperator
      MaximalPreservationCrossover <|-- CrossoverOperator
      OnePointCrossover <|-- CrossoverOperator
      UniformCrossover <|-- CrossoverOperator
      TwoPointCrossover <|-- CrossoverOperator
      OrdinalNumberMean <|-- CrossoverOperator
    }
  }
}

@enduml
